_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float rgbIntensity = 0.1 + 0.1 * sin(uTime * 3.7);
    float displaceIntensity = 0.2 + 0.3 * pow(sin(uTime * 1.2), 5.0);
    float interlaceIntensity = 0.01;
    float dropoutIntensity = 0.1;
    float displace = blockyNoise(vUv + vec2(vUv.y, 0.0), displaceIntensity, 25.0, 66.6);
    displace *= blockyNoise(vUv.yx + vec2(0.0, vUv.x), displaceIntensity, 111.0, 13.7);
    vUv.x += displace;
    vec2 offs = 0.1 * vec2(blockyNoise(vUv.xy + vec2(vUv.y, 0.0), rgbIntensity, 65.0, 341.0), 0.0);
    vec3 col = texture(sampler_main, vUv - offs).rgb;
    col.g = texture(sampler_main, vUv).g;
    col.b = texture(sampler_main, vUv + offs).b;
    float line = fract(vUv.y * uTexSize.y / 3.0);
    vec3 mask = vec3(3.0, 0.0, 0.0);
    if (line > 0.333) mask = vec3(0.0, 3.0, 0.0);
    if (line > 0.666) mask = vec3(0.0, 0.0, 3.0);
    float maskNoise = blockyNoise(vUv, interlaceIntensity, 90.0, uTime) * max(displace, offs.x);
    maskNoise = 1.0 - maskNoise;
    if (maskNoise == 1.0) mask = vec3(1, 1, 1);
    float dropout = blockyNoise(vUv, dropoutIntensity, 11.0, uTime) * blockyNoise(vUv.yx, dropoutIntensity, 90.0, uTime);
    mask *= (1.0 - 5.0 * dropout);
    ret = vec4(mask * col, 1.0);

  fragColor = ret;
}
